INSERT INTO `v1_5c18c50a89c75dc08582eb3a6d26b8df0c012f6128b1cdf2c73e388c8d151a0e` VALUES (100, "2030/01/01 14:59:59", "ミッションねえ……\nちょうどいいや\nどこまで片付けられるか\n賭けをしようじゃないか", 0.0, 3001, "2024/10/31 12:00:00", 1, "ヤマト", 2.1, -416.5, 2, 3001100, 130011);
INSERT INTO `v1_5c18c50a89c75dc08582eb3a6d26b8df0c012f6128b1cdf2c73e388c8d151a0e` VALUES (101, "2030/01/01 14:59:59", "他人から言われた任務を\n言われるままにやるなんざ\n性に合わないんだがね……\nま、報酬は貰っとこうか", 0.0, 3001, "2024/10/31 12:00:00", 4, "ヤマト", 5.68, -416.5, 2, 3001101, 130011);
INSERT INTO `v1_5c18c50a89c75dc08582eb3a6d26b8df0c012f6128b1cdf2c73e388c8d151a0e` VALUES (102, "2030/01/01 14:59:59", "なんだい？　やれンなら\nとっとと済ませちまいな。\nフブキが早くやることやれ\nってボヤいてたよ。", 0.0, 3001, "2024/10/31 12:00:00", 1, "ヤマト", 0.0, -416.5, 1, 3001102, 130011);
INSERT INTO `v1_5c18c50a89c75dc08582eb3a6d26b8df0c012f6128b1cdf2c73e388c8d151a0e` VALUES (100, "2030/01/01 14:59:59", "え～？　ぼくに頼みごと～？\nどうしちゃおっかな～\nちゃんとお願いできたら\n考えてあげよっかな～？", 0.0, 3002, "2024/10/31 12:00:00", 1, "フブキ", 0.0, -416.5, 1, 3002100, 130211);
INSERT INTO `v1_5c18c50a89c75dc08582eb3a6d26b8df0c012f6128b1cdf2c73e388c8d151a0e` VALUES (101, "2030/01/01 14:59:59", "ほらほらぁ、これが\n欲しいんでしょ～？\nほんと、しょうがないよね～\nザコおに～いさん♡", 0.0, 3002, "2024/10/31 12:00:00", 1, "フブキ", 0.0, -416.5, 1, 3002101, 130211);
INSERT INTO `v1_5c18c50a89c75dc08582eb3a6d26b8df0c012f6128b1cdf2c73e388c8d151a0e` VALUES (102, "2030/01/01 14:59:59", "へえ～、欲しいんだ～？\nぼくのた・い・せ・つ・な・モ・ノ\nあははっ！　なに考えてんの？\nもうへんふしじゃ～んｗ", 0.0, 3002, "2024/10/31 12:00:00", 5, "フブキ", 8.53, -416.5, 2, 3002102, 130211);
INSERT INTO `v1_5c18c50a89c75dc08582eb3a6d26b8df0c012f6128b1cdf2c73e388c8d151a0e` VALUES (103, "2030/01/01 14:59:59", "なになに～？　もしかしてまた\nおねだりするつもりなんだ？\nとか言って、ほんとはぼくに\n会いたいだけだったりして～？", 0.0, 3002, "2024/10/31 12:00:00", 7, "フブキ", 5.67, -416.5, 1, 3002103, 130211);
INSERT INTO `v1_5c18c50a89c75dc08582eb3a6d26b8df0c012f6128b1cdf2c73e388c8d151a0e` VALUES (104, "2030/01/01 14:59:59", "ザコお兄さんってぇ\n頼み方もワンパなのぉ～？\nもっと必死にならないと\nぼくの心は動かせないよ～？", 0.0, 3002, "2024/10/31 12:00:00", 1, "フブキ", 0.0, -416.5, 1, 3002104, 130211);
INSERT INTO `v1_5c18c50a89c75dc08582eb3a6d26b8df0c012f6128b1cdf2c73e388c8d151a0e` VALUES (300, "2030/01/01 14:59:59", "あのさーザコお兄さん、\nな～んか調子乗ってない？\nぼくのこと、なんでもくれる\nチョロいやつとか思ってたりー？", 0.0, 3004, "2024/10/31 12:00:00", 3, "フブキ", 0.0, -416.5, 3, 3002300, 130211);
INSERT INTO `v1_5c18c50a89c75dc08582eb3a6d26b8df0c012f6128b1cdf2c73e388c8d151a0e` VALUES (301, "2030/01/01 14:59:59", "ざんね～ん♪\nうざいお兄さんには、もうな～んにもあげませ～ん♡\nほんとなっさけなーい♪\nばいば～い♡", 0.0, 3005, "2024/10/31 12:00:00", 7, "フブキ", 0.0, -416.5, 7, 3002400, 130211);
INSERT INTO `v1_5c18c50a89c75dc08582eb3a6d26b8df0c012f6128b1cdf2c73e388c8d151a0e` VALUES (200, "2030/01/01 14:59:59", "きゃはは、ほんと必死～♡\nは～、面白かった。\n笑えたからいいよ～\nそれ、恵んだげる～♪", 0.0, 3003, "2024/10/31 12:00:00", 2, "フブキ", 4.4, -416.5, 1, 3003200, 130211);
INSERT INTO `v1_5c18c50a89c75dc08582eb3a6d26b8df0c012f6128b1cdf2c73e388c8d151a0e` VALUES (201, "2030/01/01 14:59:59", "は～、しょうがないな～♡\nザコお兄さんってば\nほんとよわよわで\n情けないよね～ｗ", 0.0, 3003, "2024/10/31 12:00:00", 7, "フブキ", 0.0, -416.5, 7, 3003201, 130211);
INSERT INTO `v1_5c18c50a89c75dc08582eb3a6d26b8df0c012f6128b1cdf2c73e388c8d151a0e` VALUES (202, "2030/01/01 14:59:59", "お兄さんってば、ぼくがいないと\nほんとザッコザコだよね～\nもっと感謝しろし～♪", 0.0, 3003, "2024/10/31 12:00:00", 1, "フブキ", 5.6, -416.5, 2, 3003202, 130211);
